#include <iostream>
#include <string>
#include <vector>
#include <sstream>

using namespace std;

class Book {
private:
    string title;
    string author;
    string isbn;

public:
    Book(const string& title, const string& author, const string& isbn)
        : title(title), author(author), isbn(isbn) {}

    string getTitle() {
        return title;
    }

    string getAuthor() {
        return author;
    }

    string getIsbn() {
        return isbn;
    }

    void displayBookInfo() {
        cout << "Title: " << title << endl;
        cout << "Author: " << author << endl;
        cout << "ISBN: " << isbn << endl;
    }
};

int main() {
    Book book1("The Hitchhiker's Guide to the Galaxy", "Douglas Adams", "978-0345391803");
    cout << "--- Book 1 ---" << endl;
    book1.displayBookInfo();
    cout << "--- End Book 1 ---" << endl;

    Book book2("1984", "George Orwell", "978-0451524935");
    cout << "--- Book 2 ---" << endl;
    book2.displayBookInfo();
    cout << "--- End Book 2 ---" << endl;

    Book book3("", "Unknown Author", "");
    cout << "--- Book 3 ---" << endl;
    book3.displayBookInfo();
    cout << "--- End Book 3 ---" << endl;

    return 0;
}
